import{_ as a,o as l,c as e,a2 as o}from"./chunks/framework.Pywvta2k.js";const g=JSON.parse('{"title":"易水学派","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/01-易水学派（张元素）.md","filePath":"tcm-data/03-宋金元/01-易水学派（张元素）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/03-宋金元/01-易水学派（张元素）.md"};function i(n,t,s,h,d,u){return l(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="易水学派" tabindex="-1">易水学派 <a class="header-anchor" href="#易水学派" aria-label="Permalink to &quot;易水学派&quot;">​</a></h1><blockquote><p>张元素（约1131-1234年），河北易县人 金元四大家之前驱，&quot;脏腑辨证&quot;的体系化者 师从/传承：张元素 → 李东垣 → 王好古</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字洁古</li><li><strong>生卒</strong>：约1131-1234年（金代）</li><li><strong>籍贯</strong>：河北易县（易水）</li><li><strong>代表著作</strong>：《医学启源》《脏腑标本寒热虚实用药式》</li></ul><h3 id="历史典故" tabindex="-1">历史典故 <a class="header-anchor" href="#历史典故" aria-label="Permalink to &quot;历史典故&quot;">​</a></h3><p>张元素因曾试进士不第而学医，27岁时因治愈名医刘完素（河间）的伤寒病而声名鹊起。（刘完素当时拒服他的方，但被迫服后竟愈——从此&quot;张刘&quot;齐名。）</p><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-脏腑辨证-用药式" tabindex="-1">1. 脏腑辨证（用药式） <a class="header-anchor" href="#_1-脏腑辨证-用药式" aria-label="Permalink to &quot;1. 脏腑辨证（用药式）&quot;">​</a></h3><p>张元素的最大贡献是：<strong>将药物的功效与脏腑的虚实寒热直接对应</strong>。他制定了一套&quot;<strong>脏腑标本寒热虚实用药式</strong>&quot;：</p><p><strong>以肝为例：</strong></p><ul><li>肝实：泻肝（青皮、芍药）</li><li>肝虚：补肝（当归、川芎）</li><li>肝寒：温肝（肉桂、吴萸）</li><li>肝热：清肝（黄芩、龙胆草）</li></ul><p>这种&quot;对号入座&quot;式的用药体系，极大提高了临床用药的精准性。</p><h3 id="_2-气味厚薄理论" tabindex="-1">2. 气味厚薄理论 <a class="header-anchor" href="#_2-气味厚薄理论" aria-label="Permalink to &quot;2. 气味厚薄理论&quot;">​</a></h3><blockquote><p><strong>「药有气味厚薄，升降浮沉。」</strong></p></blockquote><ul><li>味薄者升（如桂枝、川芎）</li><li>味厚者沉（如大黄、芒硝）</li><li>气薄者降（如黄芩、黄连）</li><li>气厚者浮（如附子、肉桂）</li></ul><h3 id="_3-引经报使" tabindex="-1">3. 引经报使 <a class="header-anchor" href="#_3-引经报使" aria-label="Permalink to &quot;3. 引经报使&quot;">​</a></h3><blockquote><p><strong>「用药须引经，庶不泛泛。」</strong></p></blockquote><p>每味药有<strong>专入某经</strong>的特性：</p><ul><li>太阳经：羌活</li><li>阳明经：白芷、升麻</li><li>少阳经：柴胡</li><li>太阴经：苍术</li><li>少阴经：独活</li><li>厥阴经：细辛</li></ul><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>九味羌活汤</strong></td><td style="text-align:left;">羌活、防风、苍术、细辛、川芎、白芷、生地、黄芩、甘草</td><td style="text-align:left;">外感风寒湿</td></tr><tr><td style="text-align:left;"><strong>枳术丸</strong></td><td style="text-align:left;">枳实、白术（荷叶裹烧饭为丸）</td><td style="text-align:left;">脾胃虚弱，食积不化</td></tr></tbody></table><p><strong>枳术丸</strong>源自张元素，后被李东垣发扬。黄元御《四圣心源》中的<strong>黄芽汤</strong>（人参、甘草、茯苓、干姜）与张元素的健脾胃思路一脉相承。</p><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「运气不齐，古今异轨，古方今病，不相能也。」</strong></p></blockquote><blockquote><p><strong>「前人用药，各有所长。伤寒宗仲景，热病用刘氏。」</strong></p></blockquote><blockquote><p><strong>「药有气味厚薄，升降浮沉。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="直接影响" tabindex="-1">直接影响 <a class="header-anchor" href="#直接影响" aria-label="Permalink to &quot;直接影响&quot;">​</a></h3><ul><li>弟子<strong>李东垣</strong> → 创《脾胃论》，成为补土派宗师</li><li>再传<strong>王好古</strong> → 《阴证略例》，发挥阴证论</li></ul><h3 id="间接影响" tabindex="-1">间接影响 <a class="header-anchor" href="#间接影响" aria-label="Permalink to &quot;间接影响&quot;">​</a></h3><ul><li>黄元御&quot;脏腑用药&quot;深受张元素的影响</li><li>张元素的&quot;引经报使&quot;至今仍是中药处方的重要原则</li></ul><hr><p><em>本条目为精简框架版。可扩展至张元素脏腑用药式完整表格、与李东垣的对比等内容。</em></p>',38)])])}const q=a(r,[["render",i]]);export{g as __pageData,q as default};
